prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "fbb0adafe6924f58ac902063a36646fe" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model bbo:id ?bboId . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "fbb0adafe6924f58ac902063a36646fe") || 
         CONTAINS(LCASE(STR(?normalizedId)), "fbb0adafe6924f58ac902063a36646fe") ||
         CONTAINS(LCASE(STR(?bboId)), "fbb0adafe6924f58ac902063a36646fe"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?direction ?outgoingCount WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_e0cff846_e631_4657_9d55_ab4c98968cd7> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  {
    SELECT ?gateway (COUNT(?outEdge) AS ?outgoingCount) WHERE {
      ?gateway a bboExt:ExclusiveGateway .
      ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_e0cff846_e631_4657_9d55_ab4c98968cd7> .
      ?outEdge a bbo:SequenceFlow .
      ?outEdge bbo:has_sourceRef ?gateway .
    }
    GROUP BY ?gateway
  }
}
ORDER BY ?gatewayName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Let me trace the exact flow structure by looking at incoming/outgoing edges for each node
SELECT ?node ?nodeName ?incomingCount ?outgoingCount WHERE {
  ?node tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_e0cff846_e631_4657_9d55_ab4c98968cd7> .
  ?node a ?type .
  FILTER(?type IN (bboExt:StartEvent, bboExt:EndEvent, bboExt:ExclusiveGateway, bboExt:ChoreographyTask))
  OPTIONAL { ?node bbo:name ?nodeName . }
  {
    SELECT ?node (COUNT(?inEdge) AS ?incomingCount) WHERE {
      ?inEdge a bbo:SequenceFlow .
      ?inEdge bbo:has_targetRef ?node .
    }
    GROUP BY ?node
  }
  {
    SELECT ?node (COUNT(?outEdge) AS ?outgoingCount) WHERE {
      ?outEdge a bbo:SequenceFlow .
      ?outEdge bbo:has_sourceRef ?node .
    }
    GROUP BY ?node
  }
}
ORDER BY ?nodeName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Let me get the actual URIs for the empty-named elements to understand the structure better
SELECT ?elem ?type ?incoming ?outgoing WHERE {
  ?elem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_e0cff846_e631_4657_9d55_ab4c98968cd7> .
  ?elem a ?type .
  FILTER NOT EXISTS { ?elem bbo:name ?name . }
  {
    SELECT ?elem (COUNT(?inEdge) AS ?incoming) WHERE {
      ?inEdge a bbo:SequenceFlow .
      ?inEdge bbo:has_targetRef ?elem .
    }
    GROUP BY ?elem
  }
  {
    SELECT ?elem (COUNT(?outEdge) AS ?outgoing) WHERE {
      ?outEdge a bbo:SequenceFlow .
      ?outEdge bbo:has_sourceRef ?elem .
    }
    GROUP BY ?elem
  }
}
ORDER BY ?type
